INSERT INTO content_blocks (section_key, title, subtitle, icon, enabled, sort_order, items) VALUES
('hero', 'Welcome to God''s House', 'A loving community in the heart of Nepal, worshipping Jesus and serving our neighbours with joy.', 'Sparkles', true, 0, '[{"text":"Faith • Hope • Love","type":"tagline"}]');
INSERT INTO content_blocks (section_key, title, subtitle, icon, enabled, sort_order, items) VALUES
('what_to_expect', 'First Time Here?', 'Thinking about visiting? Here are answers to the questions most people have before their first Sunday.', 'Clock', true, 1, '[{"q":"How long is the service?","a":"Around 90 minutes — worship, a practical Bible message, and time to connect over tea afterwards."},{"q":"What should I wear?","a":"Come as you are."},{"q":"What about my kids?","a":"Safe, fun children''s ministry runs during the service, with trained volunteers and easy check-in."},{"q":"What is worship like?","a":"Heartfelt, joyful singing in Nepali and English, led by our worship team."},{"q":"Where do I park?","a":"Free parking beside the church, short walk from Baneshwor bus stop."},{"q":"Will I be singled out?","a":"Never. There is no pressure to give or stand up. Come, relax, and experience God''s family."}]');
INSERT INTO content_blocks (section_key, title, subtitle, icon, enabled, sort_order, items) VALUES
('welcome', 'A Word of Welcome', 'Dear friend, whether you are exploring faith for the first time or looking for a church home, you are so welcome here. Our prayer is that you would encounter the love of Jesus and find a family that walks with you.', 'Heart', true, 2, '[{"label":"Members","value":"850+"},{"label":"Ministries","value":"12"},{"label":"Years Serving","value":"18"},{"label":"Villages Reached","value":"24"}]');
INSERT INTO content_blocks (section_key, title, subtitle, icon, enabled, sort_order, items) VALUES
('what_we_believe', 'What We Believe', 'No complicated words — just the heart of our faith, in plain language.', 'BookOpen', true, 3, '[{"title":"The Bible","desc":"God''s Word is our guide for life and faith — trustworthy, living, and for everyone."},{"title":"God''s Love","desc":"We believe in one loving God who created you, knows you, and wants a relationship with you."},{"title":"Jesus","desc":"Jesus lived, died, and rose again so that anyone — no matter their past — can be made new."},{"title":"Community","desc":"Faith grows in family. We do life together — welcoming all, from every village and background."},{"title":"Mission","desc":"We''re called to share hope and serve our neighbours across Nepal with practical love."},{"title":"New Life","desc":"God''s grace is a free gift. There''s nothing to earn — just come as you are and be transformed."}]');
INSERT INTO content_blocks (section_key, title, subtitle, icon, enabled, sort_order, items) VALUES
('watch_online', 'Watch Online', 'Can''t make it in person? Worship with us online. Watch our latest message or join the live service every Sunday at 10:00 AM — wherever you are.', 'Play', true, 4, '[]');
INSERT INTO content_blocks (section_key, title, subtitle, icon, enabled, sort_order, items) VALUES
('prayer_cta', 'Need Prayer?', 'Our prayer team would be honoured to stand with you. Every request is kept confidential.', 'HandHeart', true, 5, '[]');
